  const statusDiv = api.createElement('div', {
    style: 'padding: 40px; text-align: center; color: #999; font-style: italic;'
  }, ['Type to search across all items...']);
  resultsContainer.appendChild(statusDiv);

  // Results list
  const resultsList = api.createElement('div', {
    style: 'display: none; max-height: 600px; overflow-y: auto;'
  }, []);
  resultsContainer.appendChild(resultsList);

  // Search function
  let searchTimeout = null;
  const performSearch = async (query, skipSave = false) => {
    if (!skipSave) {
      if (searchTimeout) {
        clearTimeout(searchTimeout);
      }
      searchTimeout = setTimeout(async () => {
        await saveQueryAndSearch(query);
      }, 300);
    } else {
      await executeSearch(query);
    }
  };

  const saveQueryAndSearch = async (query) => {
    const updated = {
      ...search,
      content: {
        ...search.content,
        currentQuery: query
      }
    };
    await api.update(updated);
    await executeSearch(query);
  };

  const executeSearch = async (query) => {
    if (!query || query.trim().length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.textContent = 'Type to search across all items...';
      return;
    }

    statusDiv.style.display = 'block';
    resultsList.style.display = 'none';
    statusDiv.textContent = 'Searching...';

    const targetContainer = search.content.target_container;
    let itemsToSearch;

    if (targetContainer) {
      const container = await api.get(targetContainer);
      const childIds = (container.children || []).map(c =>
        typeof c === 'string' ? c : c.id
      );
      itemsToSearch = await Promise.all(
        childIds.map(id => api.get(id).catch(() => null))
      );
      itemsToSearch = itemsToSearch.filter(i => i !== null);
    } else {
      itemsToSearch = await api.getAll();
    }

    const queryLower = query.toLowerCase();
    const matches = itemsToSearch.filter(item => {
      const searchableText = [
        item.name,
        item.content?.title,
        item.content?.body,
        item.content?.description,
        JSON.stringify(item.content)
      ].filter(Boolean).join(' ').toLowerCase();

      return searchableText.includes(queryLower);
    });

    matches.sort((a, b) => b.modified - a.modified);

    if (matches.length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.textContent = 'No items found matching "' + query + '"';
    } else {
      statusDiv.style.display = 'none';
      resultsList.style.display = 'block';
      resultsList.innerHTML = '';

      const countHeader = api.createElement('div', {
        style: 'margin-bottom: 15px; font-size: 14px; color: #666; font-weight: 500;'
      }, ['Found ' + matches.length + ' item' + (matches.length === 1 ? '' : 's')]);
      resultsList.appendChild(countHeader);

      matches.forEach(item => {
        const resultDiv = api.createElement('div', {
          style: 'padding: 12px; margin-bottom: 8px; background: white; border: 1px solid #ddd; border-radius: 6px; cursor: pointer; transition: all 0.2s;'
        }, []);

        const itemTitle = api.createElement('div', {
          style: 'font-weight: 500; color: #333; margin-bottom: 6px; font-size: 15px;'
        }, [item.name || item.content?.title || item.id]);
        resultDiv.appendChild(itemTitle);

        const previewText = item.content?.body || item.content?.description ||
                           JSON.stringify(item.content).substring(0, 150);
        const preview = api.createElement('div', {
          style: 'font-size: 13px; color: #666; margin-bottom: 6px; line-height: 1.4; overflow: hidden; text-overflow: ellipsis; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical;'
        }, [previewText.substring(0, 200)]);
        resultDiv.appendChild(preview);

        const meta = api.createElement('div', {
          style: 'font-size: 12px; color: #999;'
        }, [
          'Type: ' + item.type.substring(0, 8) + '... | Modified: ' +
          new Date(item.modified).toLocaleDateString()
        ]);
        resultDiv.appendChild(meta);

        resultDiv.onclick = () => {
          api.openSibling(item.id);
        };

        resultDiv.onmouseover = () => {
          resultDiv.style.background = '#f8f9fa';
          resultDiv.style.borderColor = '#3b82f6';
          resultDiv.style.transform = 'translateX(4px)';
        };
        resultDiv.onmouseout = () => {
          resultDiv.style.background = 'white';
          resultDiv.style.borderColor = '#ddd';
          resultDiv.style.transform = 'translateX(0)';
        };

        resultsList.appendChild(resultDiv);
      });
    }
  };

  input.oninput = (e) => {
    performSearch(e.target.value);
  };

  if (savedQuery && savedQuery.trim().length > 0) {
    await executeSearch(savedQuery);
  }

  return container;
}

export async function render(item, api) {
  const container = api.createElement('div', { style: 'padding: 15px;' }, []);

  // Header
  const header = api.createElement('h3', { style: 'margin-top: 0;' }, [
    item.name || 'Untitled Script'
  ]);
  container.appendChild(header);

  // Description
  if (item.content.description) {
    const desc = api.createElement('p', { style: 'color: #666; font-style: italic;' }, [
      item.content.description
    ]);
    container.appendChild(desc);
  }

  // Code display
  const code = api.createElement('pre', {
    style: `
      background: #f8f8f8;
      padding: 15px;
      border-radius: 4px;
      border: 1px solid #ddd;
      overflow-x: auto;
      font-family: 'SF Mono', Monaco, monospace;
      font-size: 13px;
      line-height: 1.5;
    `
  }, [item.content.code || '// No code']);
  container.appendChild(code);

  // Buttons
  const buttons = api.createElement('div', { 
    style: 'margin-top: 15px; display: flex; gap: 10px;' 
  }, []);

  const runBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px; font-weight: 500;',
    onclick: async () => {
      runBtn.disabled = true;
      runBtn.textContent = 'Running...';

      try {
        // Get the REPL API which has the helper functions
        const replApi = window.kernel.createREPLAPI();

        // Execute the script code with REPL API
        const asyncFn = new Function('api', `
          return (async () => {
            ${item.content.code}
          })();
        `);

        const result = await asyncFn(replApi);
        alert('Script executed!\n\nResult: ' + (
          result !== undefined 
            ? JSON.stringify(result, null, 2) 
            : 'No return value'
        ));
      } catch (error) {
        alert('Error executing script:\n\n' + error.message);
      } finally {
        runBtn.disabled = false;
        runBtn.textContent = 'Run Script';
      }
    }
  }, ['Run Script']);
  buttons.appendChild(runBtn);

  const editBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      // Navigate to raw editor for this item
      window.kernel.editItemRaw(item.id);
    }
  }, ['Edit']);
  buttons.appendChild(editBtn);

  const copyBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      navigator.clipboard.writeText(item.content.code);
      copyBtn.textContent = 'Copied!';
      setTimeout(() => copyBtn.textContent = 'Copy Code', 1000);
    }
  }, ['Copy Code']);
  buttons.appendChild(copyBtn);

  container.appendChild(buttons);

  return container;
}

// Minimal marked.js implementation - just what we need
// Full library: https://cdn.jsdelivr.net/npm/marked@11.1.1/marked.min.js

const marked = (() => {
  const block = {
    newline: /^\n+/,
    code: /^( {4}[^\n]+\n*)+/,
    heading: /^ {0,3}(#{1,6})(?=\s|$)(.*)(?:\n+|$)/,
    hr: /^ {0,3}((?:- *){3,}|(?:_ *){3,}|(?:\* *){3,})(?:\n+|$)/,
    blockquote: /^( {0,3}> ?(>| )?(.*(?:\n(?! {0,3}\[)[^\n]+)*)(?:\n+|$))+/,
    list: /^( {0,3})(bull) [\s\S]+?(?:hr|def|\n{2,}(?! )(?!\1bull )\n*|\s*$)/,
    paragraph: /^([^\n]+(?:\n(?!hr|heading|blockquote)[^\n]+)*)/,
    text: /^[^\n]+/
  };

  const inline = {
    escape: /^\\([!"#$%&'()*+,\-./:;<=>?@\[\\\]^_`{|}~])/,
    link: /^!?\[((?:\[[^\]]*\]|[^\[\]]|\](?=[^\[]*\]))*)\]\(\s*<?(.*?)>?(?:\s+['"](.*?)['"])?\s*\)/,
    strong: /^__(.*?)__(?!_)|^\*\*(.*?)\*\*(?!\*)/,
    em: /^\b_((?:__|[^_])+?)_\b|^\*((?:\*\*|[^\*])+?)\*(?!\*)/,
    code: /^`([^`]|[^`][\s\S]*?[^`])`/,
    br: /^ {2,}\n(?!\s*$)/,
    text: /^[\s\S]+?(?=[\\<!\[_*`]| {2,}\n|$)/
  };

  function escape(html) {
    return html
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function parseInline(src) {
    let out = '';
    let cap;

    while (src) {
      // escape
      if (cap = inline.escape.exec(src)) {
        src = src.substring(cap[0].length);
        out += escape(cap[1]);
        continue;
      }

      // link
      if (cap = inline.link.exec(src)) {
        src = src.substring(cap[0].length);
        const text = cap[1];
        const href = cap[2];
        out += '<a href="' + escape(href) + '">' + parseInline(text) + '</a>';
        continue;
      }

      // strong
      if (cap = inline.strong.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<strong>' + parseInline(cap[2] || cap[1]) + '</strong>';
        continue;
      }

      // em
      if (cap = inline.em.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<em>' + parseInline(cap[2] || cap[1]) + '</em>';
        continue;
      }

      // code
      if (cap = inline.code.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<code>' + escape(cap[1].trim()) + '</code>';
        continue;
      }

      // br
      if (cap = inline.br.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<br>';
        continue;
      }

      // text
      if (cap = inline.text.exec(src)) {
        src = src.substring(cap[0].length);
        out += escape(cap[0]);
        continue;
      }

      if (src) {
        throw new Error('Infinite loop on byte: ' + src.charCodeAt(0));
      }
    }

    return out;
  }

  function parse(src) {
    let out = '';
    let cap;

    src = src.replace(/\r\n|\r/g, '\n').replace(/\t/g, '    ');

    while (src) {
      // newline
      if (cap = block.newline.exec(src)) {
        src = src.substring(cap[0].length);
        continue;
      }

      // code block
      if (cap = block.code.exec(src)) {
        src = src.substring(cap[0].length);
        const code = cap[0].replace(/^ {4}/gm, '');
        out += '<pre><code>' + escape(code.trim()) + '</code></pre>\n';
        continue;
      }

      // heading
      if (cap = block.heading.exec(src)) {
        src = src.substring(cap[0].length);
        const level = cap[1].length;
        const text = cap[2].trim();
        out += '<h' + level + '>' + parseInline(text) + '</h' + level + '>\n';
        continue;
      }

      // hr
      if (cap = block.hr.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<hr>\n';
        continue;
      }

      // blockquote
      if (cap = block.blockquote.exec(src)) {
        src = src.substring(cap[0].length);
        const quote = cap[0].replace(/^ *> ?/gm, '');
        out += '<blockquote>\n' + parse(quote) + '</blockquote>\n';
        continue;
      }

      // paragraph
      if (cap = block.paragraph.exec(src)) {
        src = src.substring(cap[0].length);
        const text = cap[1].trim();
        out += '<p>' + parseInline(text) + '</p>\n';
        continue;
      }

      // text (fallback)
      if (cap = block.text.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<p>' + parseInline(cap[0]) + '</p>\n';
        continue;
      }

      if (src) {
        throw new Error('Infinite loop on byte: ' + src.charCodeAt(0));
      }
    }

    return out;
  }

  return { parse };
})();

export default marked;

